function toggleFullscreen() {
    let col = document.getElementById('previewColumn'); let btn = document.getElementById('toggleFullBtn');
    isFullscreen = !isFullscreen;
    if(isFullscreen) {
        col.classList.add('fullscreen-mode');
        btn.innerHTML = '✖ ĐÓNG TOÀN MÀN HÌNH'; btn.style.background = '#e74c3c';
        isAutoFit = true; lastFitZoom = 0; updateZoomUI(); // Tự Fit bề ngang khi vào Fullscreen
    } else {
        col.classList.remove('fullscreen-mode');
        btn.innerHTML = '🔲 TOÀN MÀN HÌNH'; btn.style.background = '#34495e';
        isAutoFit = true; lastFitZoom = 0; updateZoomUI();
    }
}

function fitZoom(){ isAutoFit = true; lastFitZoom = 0; updateZoomUI(); }

function applyZoom(val){ val = parseInt(val); if(val < 10) val = 10; if(val > 300) val = 300; currentZoom = val; isAutoFit = false; updateZoomUI(); }

function updateZoomUI(){
    const canvas = document.getElementById('preview'); const wrapper = document.getElementById('canvasWrapper');
    if(!canvas || !canvas.width) return;
    if (isAutoFit) {
        const ratioW = (wrapper.clientWidth - 20) / canvas.width;
        const ratioH = (wrapper.clientHeight - 20) / canvas.height;
        
        let z = isFullscreen ? Math.floor(ratioW * 100) : Math.floor(Math.min(ratioW, ratioH, 2.5) * 100);
        if (z < 10) z = 10;
        if (lastFitZoom > 0 && Math.abs(z - lastFitZoom) <= 2) { z = lastFitZoom; } else { lastFitZoom = z; }
        currentZoom = z;
    }
    document.getElementById('zoomSlider').value = currentZoom; document.getElementById('zoomVal').innerText = currentZoom + '%';
    canvas.style.width = (canvas.width * currentZoom / 100) + 'px'; canvas.style.height = (canvas.height * currentZoom / 100) + 'px';
}

window.addEventListener('resize',()=>{if(isAutoFit) updateZoomUI();});

