function setupFontUpload(id){let el=document.getElementById(id+'File');if(!el)return;el.addEventListener('change',e=>{let file=e.target.files[0];if(!file)return;let reader=new FileReader();reader.onload=async function(evt){let fontName=file.name.replace(/\.(ttf|otf)$/i,'');let fontData=evt.target.result;try{const fontFace=new FontFace(fontName,`url('${fontData}')`);await fontFace.load();document.fonts.add(fontFace);}catch(err){alert("Lỗi font!");return;}let sel=document.getElementById(id);let grp=document.getElementById(id+'_grpCust');let opt=document.createElement('option');opt.value=fontName;opt.text=fontName;grp.appendChild(opt);sel.value=fontName; debouncedSave(); updatePreviewImmediate();};reader.readAsDataURL(file);});} fontSelectIds.forEach(id=>setupFontUpload(id));
