function formatPriceString(str){
    if(!str || str.trim()==='') return ''; let prefix = document.getElementById('pricePrefix') ? document.getElementById('pricePrefix').value : ''; let suffix = document.getElementById('priceSuffix') ? document.getElementById('priceSuffix').value : ''; let mode = document.getElementById('priceFormatMode') ? document.getElementById('priceFormatMode').value : 'auto'; let res = str;
    if (mode === 'extract_num') { let numOnly = str.replace(/\D/g, ''); if (numOnly !== '') { res = parseInt(numOnly).toLocaleString('vi-VN'); } } 
    else if (mode !== 'raw') { let clean = str.replace(/[.,]/g,''); let v = parseFloat(clean); let hasLetters = /[a-zA-Z]/.test(str); 
        if(!hasLetters && !isNaN(v)){
            if(mode === 'auto'){ if(v>=1000000000) res = parseFloat((v/1000000000).toFixed(2))+" Tỷ"; else if(v>=1000000) res = parseFloat((v/1000000).toFixed(2))+" Tr"; else if(v>=1000) res = parseFloat((v/1000).toFixed(1))+"K"; else res = v.toLocaleString('vi-VN'); }
            else if (mode === 'div1m'){ res = parseFloat((v/1000000).toFixed(2)).toLocaleString('vi-VN'); }
            else if (mode === 'div1k'){ res = parseFloat((v/1000).toFixed(2)).toLocaleString('vi-VN'); }
            else if (mode === 'comma'){ res = v.toLocaleString('vi-VN'); }
        }
    } return prefix + res + suffix;
}

function getMenhFromPhone(phone){let d=phone.replace(/\D/g,'').split('').map(Number); if(d.length===0)return''; let s=d.reduce((a,b)=>a+b,0); while(s>=10)s=s.toString().split('').map(Number).reduce((a,b)=>a+b,0); if(s===1)return'THỦY'; if([2,5,8].includes(s))return'THỔ'; if([3,4].includes(s))return'MỘC'; if([6,7].includes(s))return'KIM'; if(s===9)return'HỎA'; return'';}
const menhColors={'THỦY':'#0066ff','THỔ':'#8b4513','MỘC':'#0a8f0a','KIM':'#ff9900','HỎA':'#ff0000'}; const menhTrung={'THỦY':'Thuỷ','THỔ':'Thổ','MỘC':'Mộc','KIM':'Kim','HỎA':'Hoả'};

function parseList(){ 
    let lines = document.getElementById('list').value.split('\n'); 
    let out = []; 
    let filterEl = document.getElementById('filterMenh'); 
    let filter = filterEl ? filterEl.value : 'ALL'; 
    lines.forEach(line=>{ 
        try { line = line.replace(/[^\p{L}\p{N}\s.,\-|/=+]/gu, '').trim(); } catch(e) {} 
        if(!line) return; 
        line = line.replace(/^[\-.,=+|/]+\s*/, ''); 
        
        // Nếu có dấu | thì ưu tiên tách bằng |, nếu không thì tách bằng khoảng trắng như cũ
        let p;
        if (line.includes('|')) p = line.split(/\s*\|\s*/);
        else p = line.replace(/\s*=\s*/g, ' ').replace(/\s+-\s+/g, ' ').split(/\s+/);
        
        let num = p[0] || ""; 
        let price = p[1] || ""; 
        let data1 = p[2] || "";
        let data2 = p.slice(3).join(' ') || ""; // Tất cả những gì còn dư nhét vào data2

        if(filter !== 'ALL'){ let m = getMenhFromPhone(num); if(m !== filter) return; } 
        out.push([num, price, data1, data2]); 
    }); 
    return out; 
}

