function loadBuiltinTemplate(key) { if(!key || !BUILTIN_TEMPLATES[key]) return; let rawData = BUILTIN_TEMPLATES[key]; if(rawData === "" || rawData.startsWith("DÁN_ĐOẠN_MÃ")) { alert("Chưa có mã LITE!"); document.getElementById('builtinTemplates').value = ""; return; } try { let cfg; try { cfg = JSON.parse(rawData); } catch(e1) { try { cfg = JSON.parse(decodeURIComponent(escape(atob(rawData.replace(/\s+/g, ''))))); } catch(e2) { cfg = JSON.parse(atob(rawData.replace(/\s+/g, ''))); } } applyConfigToUI(cfg, true); document.getElementById('builtinTemplates').value = ""; alert("✅ Nạp mẫu thành công!"); } catch (err) { console.error(err); alert("❌ Lỗi nạp mẫu: " + err.message); document.getElementById('builtinTemplates').value = ""; } }
function applyConfigToUI(cfg, isTemplate = false) { 
    let listEl = document.getElementById('list');
    let currentListBackup = listEl ? listEl.value : "";
    fontSelectIds.forEach(function(id) { 
        if (cfg['custom_list_' + id]) { 
            var grp = document.getElementById(id + '_grpCust'); 
            cfg['custom_list_' + id].forEach(function(f) { 
                if (f.data) { 
                    try { localStorage.setItem('font_data_' + f.name, f.data); } catch (err) {} 
                    var style = document.createElement('style'); 
                    style.innerHTML = "@font-face { font-family: '" + f.name + "'; src: url('" + f.data + "'); }"; 
                    document.head.appendChild(style); 
                    if (grp) { 
                        var exists = false; 
                        for (var i = 0; i < grp.children.length; i++) { if (grp.children[i].value === f.name) exists = true; } 
                        if (!exists) { var opt = document.createElement('option'); opt.value = f.name; opt.text = f.name; grp.appendChild(opt); } 
                    } 
                } 
            }); 
        } 
    }); 
    for(let k in cfg){ 
        if(['list', 'filterMenh', 'pageInput'].includes(k)) continue; 
        let el=document.getElementById(k); 
        if(el){ 
            if(el.type==='checkbox') el.checked=cfg[k]; 
            else el.value=cfg[k]; 
        } 
    } 
    if (cfg.bgImage) { bgImage = new Image(); bgImage.src = cfg.bgImage; bgImage.onload = function() { isAutoFit = true; updatePreviewImmediate(); debouncedSave(); }; } else { bgImage = null; } 
    if (cfg.cellBgImage) { cellBgImage = new Image(); cellBgImage.src = cfg.cellBgImage; cellBgImage.onload = function() { isAutoFit = true; updatePreviewImmediate(); debouncedSave(); }; } else { cellBgImage = null; } 
    if (listEl) listEl.value = currentListBackup;
    currentStep = 0; updateUI(); document.getElementById('importConfig').value = ''; updatePreviewImmediate(); debouncedSave(); 
}
