// ==========================================
// 8. QUICK SLIDER & KHỞI TẠO BẮT ĐẦU (ĐỒNG BỘ 2 CHIỀU)
// ==========================================
let originalValue = 0; let currentEditingInput = null; let longPressTimer = null;

// Hàm đóng thanh trượt và trả về vị trí gốc
function closeQuickSlider() {
    const qsContainer = document.getElementById('quickSliderContainer');
    if(qsContainer) {
        qsContainer.style.display = 'none';
        currentEditingInput = null;
        sliderMoved = false; 
        qsContainer.style.top = ''; qsContainer.style.left = '50%'; qsContainer.style.bottom = '20px'; qsContainer.style.transform = 'translateX(-50%)';
    }
}

// ĐỒNG BỘ NGƯỢC: Gõ số ở bảng tùy chỉnh -> Thanh trượt & Ô số trượt chạy theo
document.addEventListener('input', function(e) {
    if (currentEditingInput && e.target === currentEditingInput) {
        let v = parseFloat(e.target.value) || 0;
        let slider = document.getElementById('quickSlider');
        let sliderInput = document.getElementById('quickSliderValueInput');
        if(slider) slider.value = v;
        if(sliderInput) sliderInput.value = v;
    }
});

// BẮT SỰ KIỆN KHI BẤM VÀO Ô NHẬP SỐ ĐỂ MỞ THANH TRƯỢT
document.addEventListener('focusin', function(e) {
    if (e.target.tagName === 'INPUT' && e.target.type === 'number') {
        const input = e.target;
        if(input.id === 'quickSliderValueInput' || input.id === 'pageInput') return;
        
        currentEditingInput = input;
        originalValue = parseFloat(input.value) || 0;
        
        const sliderContainer = document.getElementById('quickSliderContainer');
        const slider = document.getElementById('quickSlider');
        const sliderInput = document.getElementById('quickSliderValueInput');
        const sliderLabel = document.getElementById('quickSliderLabel');
        
        let labelText = "Chỉnh thông số";
        const row = input.closest('.setting-row');
        if (row) { const label = row.querySelector('label'); if (label) labelText = label.innerText; } 
        else { const span = input.previousElementSibling; if (span && span.tagName === 'SPAN') labelText = span.innerText; }
        sliderLabel.innerText = labelText;
        
        let currentVal = parseFloat(input.value) || 0;
        let min = 0, max = 100, step = 1;
        if (input.id.includes('ScaleY')) { min = 0.1; max = 3; step = 0.1; }
        else if (input.id.includes('Angle')) { min = -360; max = 360; step = 1; }
        else if (input.id.includes('Pad')) { min = 0; max = 100; step = 1; }
        else if (input.id.includes('Size') || input.id.includes('TextScale')) { min = 8; max = 150; step = 1; }
        else if (input.id.includes('W') || input.id.includes('H') || input.id.includes('Width') || input.id.includes('Height')) { min = 0; max = 800; step = 1; }
        else if (input.id.includes('X') || input.id.includes('Y')) { min = -500; max = 500; step = 1; }
        else if (input.id.includes('Gap') || input.id.includes('Radius')) { min = 0; max = 100; step = 1; }
        
        slider.min = min; slider.max = max; slider.step = step;
        slider.value = currentVal; 
        if(sliderInput) sliderInput.value = currentVal;
        
        sliderContainer.style.display = 'block';
        
        // HÀM CẬP NHẬT TẤT CẢ (ĐỒNG BỘ XUÔI)
        const updateAll = (newVal) => {
            let v = parseFloat(newVal); if (isNaN(v)) v = 0;
            if(input.value != v) input.value = v; 
            if(slider.value != v) slider.value = v; 
            if(sliderInput && sliderInput.value != v) sliderInput.value = v;
            
            if(typeof updatePreviewImmediate === 'function') updatePreviewImmediate();
            if(typeof debouncedSave === 'function') debouncedSave();
            if(typeof showApplyButton === 'function') showApplyButton();
        };

        slider.oninput = function() { updateAll(this.value); };
        if(sliderInput) {
            sliderInput.oninput = function() { updateAll(this.value); };
            sliderInput.onkeydown = function(ev) { if(ev.key === 'Enter') { ev.preventDefault(); updateAll(this.value); } };
        }
        
        const setupBtn = (btnId, delta) => {
            const btn = document.getElementById(btnId); if(!btn) return;
            const startAction = (ev) => { ev.preventDefault(); let currentVal = parseFloat(input.value); updateAll((currentVal + delta).toFixed(step < 1 ? 1 : 0)); longPressTimer = setInterval(() => { let v = parseFloat(input.value); updateAll((v + delta).toFixed(step < 1 ? 1 : 0)); }, 80); };
            const stopAction = () => clearInterval(longPressTimer);
            btn.ontouchstart = startAction; btn.ontouchend = stopAction; btn.onmousedown = startAction; btn.onmouseup = stopAction; btn.onmouseleave = stopAction;
        };
        setupBtn('btnSliderMinus', -step); setupBtn('btnSliderPlus', step);
        document.getElementById('btnSliderReset').onclick = (ev) => { ev.preventDefault(); updateAll(originalValue); };
    }
});

// ĐÓNG THANH TRƯỢT KHI CLICK RA NGOÀI
const closeEvents = ['touchstart', 'mousedown'];
closeEvents.forEach(evt => {
    document.addEventListener(evt, function(e) {
        const container = document.getElementById('quickSliderContainer');
        if (container && container.style.display === 'block') { 
            if (!container.contains(e.target) && e.target !== currentEditingInput) { closeQuickSlider(); } 
        }
    }, {passive: true});
});

// LOGIC KÉO THẢ THANH TRƯỢT THÔNG SỐ BẰNG TIÊU ĐỀ
let isSliderDragging = false; let sliderMoved = false; let sliderStartX, sliderStartY, sliderInitX, sliderInitY;
const qsHeader = document.getElementById('quickSliderHeader');
const qsContainer = document.getElementById('quickSliderContainer');

function startQsDrag(e) {
    if (!qsHeader || !qsContainer) return;
    if (e.target.tagName === 'BUTTON' || e.target.tagName === 'INPUT') return;
    
    isSliderDragging = true;
    let clientX = e.type.includes('touch') ? e.touches[0].clientX : e.clientX;
    let clientY = e.type.includes('touch') ? e.touches[0].clientY : e.clientY;
    sliderStartX = clientX; sliderStartY = clientY;
    
    let rect = qsContainer.getBoundingClientRect();
    sliderInitX = rect.left; sliderInitY = rect.top;
    
    if(!sliderMoved) { qsContainer.style.bottom = 'auto'; qsContainer.style.transform = 'none'; }
    qsContainer.style.left = sliderInitX + 'px'; qsContainer.style.top = sliderInitY + 'px';
    qsHeader.style.cursor = 'grabbing';
}

function doQsDrag(e) {
    if (!isSliderDragging || !qsContainer) return;
    e.preventDefault();
    let clientX = e.type.includes('touch') ? e.touches[0].clientX : e.clientX;
    let clientY = e.type.includes('touch') ? e.touches[0].clientY : e.clientY;
    let dx = clientX - sliderStartX; let dy = clientY - sliderStartY;
    
    if (Math.abs(dx) > 3 || Math.abs(dy) > 3) sliderMoved = true;
    if (sliderMoved) {
        let maxX = window.innerWidth - qsContainer.offsetWidth; let maxY = window.innerHeight - qsContainer.offsetHeight;
        qsContainer.style.left = Math.max(0, Math.min(sliderInitX + dx, maxX)) + 'px';
        qsContainer.style.top = Math.max(0, Math.min(sliderInitY + dy, maxY)) + 'px';
    }
}

function stopQsDrag() { isSliderDragging = false; if (qsHeader) qsHeader.style.cursor = 'grab'; }

if (qsHeader) { qsHeader.addEventListener('mousedown', startQsDrag); qsHeader.addEventListener('touchstart', startQsDrag, {passive: false}); }
window.addEventListener('mousemove', doQsDrag, {passive: false}); window.addEventListener('touchmove', doQsDrag, {passive: false});
window.addEventListener('mouseup', stopQsDrag); window.addEventListener('touchend', stopQsDrag);

// --- KHỞI TẠO ---
async function loadConfig() { 
    if (typeof DEFAULT_START_TEMPLATE !== 'undefined' && typeof BUILTIN_TEMPLATES !== 'undefined' && BUILTIN_TEMPLATES[DEFAULT_START_TEMPLATE]) { 
        try { let rawData = BUILTIN_TEMPLATES[DEFAULT_START_TEMPLATE]; let cfg; 
            try { cfg = JSON.parse(rawData); } catch(e1) { try { cfg = JSON.parse(decodeURIComponent(escape(atob(rawData.replace(/\s+/g, ''))))); } catch(e2) { cfg = JSON.parse(atob(rawData.replace(/\s+/g, ''))); } } 
            if(typeof applyConfigToUI === 'function') applyConfigToUI(cfg, true); 
        } catch(err) {} 
    } 
    try { 
        let savedList = localStorage.getItem(STORAGE_KEY + '_list'); let elList = document.getElementById('list'); 
        if (savedList !== null && elList) { elList.value = savedList; } 
        if(typeof updateUI === 'function') updateUI(); if(typeof updatePreviewImmediate === 'function') updatePreviewImmediate(); 
    } catch(e) {} 
}

window.onload=function(){
    loadConfig(); 
    setTimeout(()=>{
        isAutoFit=true;
        if(typeof updateZoomUI === 'function') updateZoomUI(); 
        if(typeof updatePreviewImmediate === 'function') updatePreviewImmediate();
        if(typeof saveState === 'function') saveState();
    }, 200);
};

