// 10. KÍCH HOẠT ZOOM 2 NGÓN TAY TRÊN ĐIỆN THOẠI
// ==========================================
const cWrapper = document.getElementById('canvasWrapper');

cWrapper.addEventListener('touchstart', (e) => {
    if(e.touches.length === 2) {
        e.preventDefault(); // Chặn hành vi cuộn trang mặc định của trình duyệt
        // Tính khoảng cách ban đầu giữa 2 ngón tay
        initialPinchDistance = Math.hypot(
            e.touches[0].clientX - e.touches[1].clientX, 
            e.touches[0].clientY - e.touches[1].clientY
        );
        // Lấy mức zoom hiện tại trên thanh trượt
        let zoomSlider = document.getElementById('zoomSlider');
        initialPinchZoom = parseInt(zoomSlider.value) || 100;
    }
}, {passive: false});

cWrapper.addEventListener('touchmove', (e) => {
    if(e.touches.length === 2) {
        e.preventDefault(); // Chặn cuộn trang khi đang zoom
        // Tính khoảng cách mới khi di chuyển 2 ngón tay
        let currentDistance = Math.hypot(
            e.touches[0].clientX - e.touches[1].clientX, 
            e.touches[0].clientY - e.touches[1].clientY
        );
        // Tính tỷ lệ phóng to/thu nhỏ
        let scale = currentDistance / initialPinchDistance;
        let newZoom = Math.round(initialPinchZoom * scale);
        
        // Gọi hàm Zoom thủ công (đã giới hạn min 10, max 300 trong hàm applyZoom)
        applyZoom(newZoom); 
    }
}, {passive: false});

