function openHelpModal() {
    document.getElementById('helpModalOverlay').style.display = 'flex';
    document.getElementById('exportMenu').style.display = 'none'; // Tự động đóng menu thả nổi lại cho gọn
}

function closeHelpModal() {
    document.getElementById('helpModalOverlay').style.display = 'none';
}

// Click ra ngoài khoảng đen để đóng bảng hướng dẫn
document.addEventListener('click', function(e) {
    let helpOverlay = document.getElementById('helpModalOverlay');
    if (e.target === helpOverlay) {
        closeHelpModal();
    }
});

// ==========================================
// 10. HỖ TRỢ CON LĂN CHUỘT TRÊN PC (SCROLL & ZOOM)
// ==========================================
document.addEventListener('DOMContentLoaded', () => {
    // 1. Cho phép dùng con lăn chuột cuộn ngang các thanh Tab
    document.querySelectorAll('.tabs, .sub-tabs, .sub-sub-tabs').forEach(el => {
        el.addEventListener('wheel', (e) => {
            if (e.deltaY !== 0) { 
                e.preventDefault(); 
                el.scrollLeft += e.deltaY; 
            }
        }, { passive: false });
    });

    // 2. Zoom ảnh bằng [Giữ phím Ctrl + Lăn chuột] một cách an toàn
    const cw = document.getElementById('canvasWrapper');
    if(cw) {
        cw.addEventListener('wheel', function(e) {
            // Nếu người dùng đang giữ phím Ctrl
            if (e.ctrlKey) {
                e.preventDefault(); // CHẶN trình duyệt zoom toàn bộ trang web
                let currentZ = parseInt(document.getElementById('zoomSlider').value) || 100;
                let newZ = currentZ - (e.deltaY > 0 ? 10 : -10); // Lăn lên thì to, lăn xuống thì nhỏ
                if(typeof applyZoom === 'function') applyZoom(newZ);
            }
        }, { passive: false });
    }
});

(function installTabHierarchy() {
    if(document.getElementById('tab-main')) return; // Chống chạy 2 lần

    // 1. Tạo Tab Chính mới mang tên "LƯỚI & CỘT"
    let mainTab = document.createElement('div');
    mainTab.id = 'tab-main';
    mainTab.className = 'tab-content active';
    
    let subTabsHtml = `<div class="sub-tabs" id="mainSubTabs">
        <button class="sub-tab-btn active" id="btn-sub-layout" onclick="switchSubTab('sub-layout', this)">LƯỚI CHUNG</button>
    </div>`;
    mainTab.innerHTML = subTabsHtml;

    let colSettings = document.querySelector('.col-settings');
    let level1Tabs = document.querySelector('.tabs');
    if(!level1Tabs || !colSettings) return;
    colSettings.insertBefore(mainTab, level1Tabs.nextSibling);

    let subTabsContainer = mainTab.querySelector('#mainSubTabs');

    // Danh sách các Tab cần thu nhỏ và nhét vào trong
    let allTargets = [
        {id: 'layout', name: 'LƯỚI CHUNG'}, {id: 'num', name: 'SỐ'},
        {id: 'price', name: 'GIÁ'}, {id: 'menh', name: 'MỆNH'},
        {id: 'mang', name: 'MẠNG'}, {id: 'data1', name: 'DL 1'}, {id: 'data2', name: 'DL 2'}
    ];

    allTargets.forEach((t, idx) => {
        let oldTab = document.getElementById('tab-' + t.id);
        if(oldTab) {
            if(t.id !== 'layout') {
                let b = document.createElement('button');
                b.className = 'sub-tab-btn'; b.id = 'btn-sub-' + t.id; b.innerHTML = t.name;
                b.setAttribute('onclick', `switchSubTab('sub-${t.id}', this)`);
                subTabsContainer.appendChild(b);
            }

            oldTab.id = 'sub-' + t.id;
            oldTab.className = 'sub-tab-content' + (t.id === 'layout' ? ' active' : '');
            oldTab.querySelectorAll('.sub-tabs').forEach(el => el.className = 'sub-sub-tabs');
            oldTab.querySelectorAll('.sub-tab-btn').forEach(el => {
                el.className = el.className.replace('sub-tab-btn', 'sub-sub-tab-btn');
                let oc = el.getAttribute('onclick');
                if(oc) el.setAttribute('onclick', oc.replace('switchSubTab', 'switchSubSubTab'));
            });
            oldTab.querySelectorAll('.sub-tab-content').forEach(el => { el.className = el.className.replace('sub-tab-content', 'sub-sub-tab-content'); });
            mainTab.appendChild(oldTab);
        }
    });

    // 2. Viết lại thanh Menu Cấp 1
    level1Tabs.innerHTML = `
        <button class="tab-btn active" onclick="switchTab('tab-main', this)">Lưới & Cột</button>
        <button class="tab-btn" onclick="switchTab('tab-colheader', this)">Tiêu Đề</button>
        <button class="tab-btn" onclick="switchTab('tab-globaltext', this)">Chữ Góc</button>
        <button class="tab-btn" onclick="switchTab('tab-general', this)">Nền & In</button>
    `;

    let oldUpdateUI = window.updateUI;
    window.updateUI = function() {
        if(oldUpdateUI) oldUpdateUI();
        let checkDisplay = (id, chkId) => {
            let btn = document.getElementById('btn-sub-' + id);
            let chk = document.getElementById(chkId);
            let isVisible = chk ? chk.checked : true;
            if(btn) {
                btn.style.display = isVisible ? '' : 'none';
                let content = document.getElementById('sub-' + id);
                if (!isVisible && content && content.classList.contains('active')) {
                    let chungBtn = document.getElementById('btn-sub-layout');
                    if(chungBtn) switchSubTab('sub-layout', chungBtn);
                }
            }
        };
        checkDisplay('num', 'chkSo'); checkDisplay('price', 'chkGia'); checkDisplay('menh', 'chkMenh');
        checkDisplay('mang', 'chkMang'); checkDisplay('data1', 'chkData1'); checkDisplay('data2', 'chkData2');
    };

    // 3. ĐỊNH TUYẾN MOBILE MODAL (ĐÃ FIX LỖI DÍNH TRÙM TAB)
    window.openMobileModal = function(tid) {
        let targetId = ''; let mTitle = ''; let tabId = ''; let subTabId = '';
        if(['num','price','menh','mang','data1','data2'].includes(tid)) {
            targetId = 'sub-' + tid; tabId = 'tab-main'; subTabId = 'sub-' + tid;
            let names = {'num':'SỐ', 'price':'GIÁ', 'menh':'MỆNH', 'mang':'MẠNG', 'data1':'DỮ LIỆU 1', 'data2':'DỮ LIỆU 2'};
            mTitle = '⚙️ TÙY CHỈNH: CỘT ' + names[tid];
        }
        else if(tid === 'header') { targetId = 'sub-hCommon'; tabId = 'tab-colheader'; subTabId = 'sub-hCommon'; mTitle = '⚙️ CÀI ĐẶT CHUNG TIÊU ĐỀ'; }
        else if(['hNum','hPrice','hMenh','hMang','hData1','hData2'].includes(tid)) { 
            targetId = 'sub-' + tid; tabId = 'tab-colheader'; subTabId = 'sub-' + tid; 
            let names = {'hNum':'SỐ', 'hPrice':'GIÁ', 'hMenh':'MỆNH', 'hMang':'MẠNG', 'hData1':'DL1', 'hData2':'DL2'};
            mTitle = '⚙️ TIÊU ĐỀ: CỘT ' + names[tid]; 
        }
        else if(window.textBlocks && window.textBlocks.find(b => b.id === tid)) { 
            targetId = 'sub-' + tid; tabId = 'tab-globaltext'; subTabId = 'sub-' + tid; 
            mTitle = '⚙️ CHỮ: ' + window.textBlocks.find(b => b.id === tid).title.toUpperCase(); 
        }

        if(!targetId) return; let el = document.getElementById(targetId); if(!el) return;
        
        if(tabId) { let btn = document.querySelector('.tabs button[onclick*="'+tabId+'"]'); if(btn) switchTab(tabId, btn); }
        if(subTabId) { let btn = document.querySelector('.sub-tabs button[onclick*="'+subTabId+'"]'); if(btn) switchSubTab(subTabId, btn); }

        // GỌI HÀM ĐÓNG VÀ TRẢ LẠI TAB CŨ (Sửa lỗi biến môi trường)
        if(typeof closeMobileModal === 'function') closeMobileModal(); 
        
        placeholderNode = document.createComment("mobile-placeholder"); 
        el.parentNode.insertBefore(placeholderNode, el); 
        activeMobileElement = el;
        
        document.getElementById('mobileModalTitle').innerText = mTitle; 
        document.getElementById('mobileModalBody').appendChild(el); 
        el.classList.add('active'); 
        document.getElementById('mobileSettingModal').style.display = 'flex';
    };

    window.syncTabUX = function(container) {
        if(isSyncingTab || !container || !window.currentUXCategory) return;
        isSyncingTab = true;
        let tryClick = (selector) => {
            let btn = container.querySelector(selector);
            if(btn && !btn.classList.contains('active')) btn.click();
        };
        tryClick(`.sub-sub-tabs > .sub-sub-tab-btn[onclick*="${window.currentUXCategory}'"]`);
        tryClick(`.sub-tabs > .sub-tab-btn[onclick*="${window.currentUXCategory}'"]`);
        let activeSubContent = container.querySelector('.sub-tab-content.active');
        if(activeSubContent) {
            let subSubBtn = activeSubContent.querySelector(`.sub-sub-tabs > .sub-sub-tab-btn[onclick*="${window.currentUXCategory}'"]`);
            if(subSubBtn && !subSubBtn.classList.contains('active')) subSubBtn.click();
        }
        isSyncingTab = false;
    };
})();
